def is_competitive_equilibrium(prices, budgets, supplies, utility_functions):
    m = len(prices)  # number of products
    n = len(budgets)  # number of buyers

    # Step 1: Compute demand sets for each buyer
    demand_sets = []
    for i in range(n):
        # Find all bundles x where p(x) <= budgets[i] and u_i(x) is maximized
        # Simplified: assume utility is linear for demonstration
        max_utility = -float('inf')
        demand = []
        for x in itertools.product(range(10), repeat=m):  # discretized space
            bundle_price = sum(prices[j] * x[j] for j in range(m))
            if bundle_price <= budgets[i]:
                utility = utility_functions[i](x)
                if utility > max_utility:
                    max_utility = utility
                    demand = [x]
                elif utility == max_utility:
                    demand.append(x)
        demand_sets.append(demand)

    # Step 2: Check if total demand equals supply for each product
    total_demand = [0] * m
    for buyer_demand in demand_sets:
        for bundle in buyer_demand:
            for j in range(m):
                total_demand[j] += bundle[j]

    return all(abs(total_demand[j] - supplies[j]) < 1e-5 for j in range(m))

Note: This is a simplified implementation assuming discretized bundles and linear utilities for demonstration purposes.
